/* Preloader Module */
var PM = PM || {};
PM.preloader = (function () {
  function init() {
    var el = document.getElementById('preloader');
    if (!el) return;
    document.body.classList.add('preloading');
    function hide() {
      if (el.classList.contains('hidden')) return;
      el.classList.add('hidden');
      document.body.classList.remove('preloading');
      document.body.style.overflow = '';
      if (PM.animations) PM.animations.initReveal();
      if (PM.animations) PM.animations.initCounters();
      if (PM.animations) PM.animations.initTimeline();
    }
    document.addEventListener('DOMContentLoaded', function () { setTimeout(hide, 400); });
    setTimeout(hide, 1200);
  }
  return { init: init };
})();
/* Navigation Module */
var PM = PM || {};
PM.navigation = (function () {
  function init() {
    var nav = document.getElementById('nav');
    var toggle = document.getElementById('navToggle');
    var menu = document.getElementById('mobileMenu');
    var scrollProgress = document.getElementById('scrollProgress');
    var btt = document.getElementById('btt');

    if (!nav) return;

    // Scroll
    function onScroll() {
      var y = window.scrollY;
      nav.classList.toggle('scrolled', y > 50);
      if (btt) btt.classList.toggle('visible', y > 500);
      if (scrollProgress) {
        var pct = (y / (document.documentElement.scrollHeight - window.innerHeight)) * 100;
        scrollProgress.style.width = pct + '%';
      }
      updateActiveLink();
    }
    window.addEventListener('scroll', onScroll, { passive: true });
    onScroll();

    // Back to top
    if (btt) {
      btt.addEventListener('click', function () {
        window.scrollTo({ top: 0, behavior: 'smooth' });
      });
    }

    // Mobile toggle
    if (toggle && menu) {
      toggle.addEventListener('click', function () {
        toggle.classList.contains('active') ? closeMenu() : openMenu();
      });

      function openMenu() {
        toggle.classList.add('active');
        toggle.setAttribute('aria-expanded', 'true');
        menu.classList.add('open');
        document.body.style.overflow = 'hidden';
      }
      function closeMenu() {
        toggle.classList.remove('active');
        toggle.setAttribute('aria-expanded', 'false');
        menu.classList.remove('open');
        document.body.style.overflow = '';
      }

      var mobileLinks = menu.querySelectorAll('.mobile-link:not(.mobile-dropdown-trigger)');
      for (var i = 0; i < mobileLinks.length; i++) {
        mobileLinks[i].addEventListener('click', closeMenu);
      }

      // Mobile dropdown toggle
      var dropdownTriggers = menu.querySelectorAll('.mobile-dropdown-trigger');
      for (var j = 0; j < dropdownTriggers.length; j++) {
        dropdownTriggers[j].addEventListener('click', function (e) {
          e.preventDefault();
          e.stopPropagation();
          var content = this.nextElementSibling;
          this.classList.toggle('open');
          content.classList.toggle('open');
        });
      }

      var subLinks = menu.querySelectorAll('.mobile-dropdown-links a');
      for (var k = 0; k < subLinks.length; k++) {
        subLinks[k].addEventListener('click', closeMenu);
      }

      window.PM_closeMenu = closeMenu;
    }

    document.addEventListener('keydown', function (e) {
      if (e.key === 'Escape') {
        if (window.PM_closeMenu) window.PM_closeMenu();
        if (PM.lightbox) PM.lightbox.close();
      }
    });

    // Active link
    function updateActiveLink() {
      var current = '';
      var sections = document.querySelectorAll('section[id]');
      for (var i = 0; i < sections.length; i++) {
        if (window.scrollY >= sections[i].offsetTop - 180) {
          current = sections[i].id;
        }
      }
      var links = document.querySelectorAll('.nav-link');
      for (var j = 0; j < links.length; j++) {
        var href = links[j].getAttribute('href');
        links[j].classList.toggle('active', href === '#' + current);
      }
    }
  }
  return { init: init };
})();
/* Animations Module */
var PM = PM || {};
PM.animations = (function () {
  function initReveal() {
    var els = document.querySelectorAll('.reveal');
    if (!('IntersectionObserver' in window)) {
      for (var i = 0; i < els.length; i++) els[i].classList.add('visible');
      return;
    }
    var obs = new IntersectionObserver(function (entries) {
      entries.forEach(function (e) {
        if (e.isIntersecting) { e.target.classList.add('visible'); obs.unobserve(e.target); }
      });
    }, { threshold: 0.1, rootMargin: '0px 0px -40px 0px' });
    els.forEach(function (el) { obs.observe(el); });
  }

  function initCounters() {
    if (!('IntersectionObserver' in window)) return;
    var nums = document.querySelectorAll('.stat-num[data-target]');
    var obs = new IntersectionObserver(function (entries) {
      entries.forEach(function (e) {
        if (e.isIntersecting) { countUp(e.target, parseInt(e.target.dataset.target), 2000); obs.unobserve(e.target); }
      });
    }, { threshold: 0.5 });
    nums.forEach(function (n) { obs.observe(n); });
  }

  function countUp(el, end, dur) {
    var start = performance.now();
    function tick(now) {
      var p = Math.min((now - start) / dur, 1);
      el.textContent = Math.floor(end * (1 - Math.pow(1 - p, 3))).toLocaleString();
      if (p < 1) requestAnimationFrame(tick);
    }
    requestAnimationFrame(tick);
  }

  function initTimeline() {
    var steps = document.querySelectorAll('.t-step');
    var fill = document.getElementById('timelineFill');
    if (!steps.length) return;
    if (!('IntersectionObserver' in window)) {
      steps.forEach(function (s) { s.classList.add('active'); });
      return;
    }
    var obs = new IntersectionObserver(function (entries) {
      entries.forEach(function (e) {
        if (e.isIntersecting) {
          steps.forEach(function (s, i) { setTimeout(function () { s.classList.add('active'); }, i * 250); });
          if (fill) setTimeout(function () { fill.style.width = '100%'; }, steps.length * 250);
          obs.unobserve(e.target);
        }
      });
    }, { threshold: 0.3 });
    var timeline = document.querySelector('.timeline');
    if (timeline) obs.observe(timeline);
  }

  function initParallax() {
    var img = document.querySelector('.hero-bg-img');
    if (!img) return;
    var ticking = false;
    window.addEventListener('scroll', function () {
      if (!ticking) {
        requestAnimationFrame(function () {
          if (window.scrollY < window.innerHeight) {
            img.style.transform = 'translateY(' + (window.scrollY * 0.25) + 'px) scale(1.04)';
          }
          ticking = false;
        });
        ticking = true;
      }
    }, { passive: true });
  }

  return { initReveal: initReveal, initCounters: initCounters, initTimeline: initTimeline, initParallax: initParallax };
})();
/* Lightbox Module */
var PM = PM || {};
PM.lightbox = (function () {
  var lightbox, lbImg, lbCaption, items, idx;

  function init() {
    lightbox = document.getElementById('lightbox');
    lbImg = document.getElementById('lbImg');
    lbCaption = document.getElementById('lbCaption');
    items = document.querySelectorAll('.g-item');
    if (!items.length || !lightbox) return;
    idx = 0;

    for (var i = 0; i < items.length; i++) {
      (function (i) {
        items[i].addEventListener('click', function () { idx = i; open(items[i]); });
      })(i);
    }

    lightbox.querySelector('.lb-close').addEventListener('click', close);
    lightbox.addEventListener('click', function (e) { if (e.target === lightbox) close(); });
    lightbox.querySelector('.lb-prev').addEventListener('click', function () { idx = (idx - 1 + items.length) % items.length; open(items[idx]); });
    lightbox.querySelector('.lb-next').addEventListener('click', function () { idx = (idx + 1) % items.length; open(items[idx]); });

    document.addEventListener('keydown', function (e) {
      if (!lightbox.classList.contains('active')) return;
      if (e.key === 'ArrowLeft') { idx = (idx - 1 + items.length) % items.length; open(items[idx]); }
      if (e.key === 'ArrowRight') { idx = (idx + 1) % items.length; open(items[idx]); }
    });
  }

  function open(item) {
    var img = item.querySelector('img');
    var cap = item.dataset.caption;
    if (img) { lbImg.src = img.src; lbImg.alt = img.alt; }
    if (cap) lbCaption.textContent = cap;
    lightbox.classList.add('active');
    document.body.style.overflow = 'hidden';
  }

  function close() {
    if (!lightbox) return;
    lightbox.classList.remove('active');
    document.body.style.overflow = '';
  }

  return { init: init, close: close };
})();
/* Contact Form Module */
var PM = PM || {};
PM.form = (function () {
  function init() {
    var form = document.getElementById('contactForm');
    if (!form) return;

    form.addEventListener('submit', function (e) {
      e.preventDefault();
      var name = document.getElementById('cfName').value.trim();
      var btn = form.querySelector('button[type="submit"]');
      var orig = btn.innerHTML;

      btn.innerHTML = '<span>Sending...</span><i class="fas fa-spinner fa-spin"></i>';
      btn.disabled = true;

      setTimeout(function () {
        btn.innerHTML = '<span>Sent!</span><i class="fas fa-check"></i>';
        btn.style.background = '#B5C4B1';
        showMsg(form, 'Thank you, ' + name + '! We will reach out shortly.', 'success');
        setTimeout(function () {
          btn.innerHTML = orig;
          btn.disabled = false;
          btn.style.background = '';
          form.reset();
        }, 3000);
      }, 1200);
    });
  }

  function showMsg(parent, text, type) {
    var old = parent.querySelector('.form-msg');
    if (old) old.remove();
    var div = document.createElement('div');
    div.className = 'form-msg';
    div.textContent = text;
    div.style.cssText = 'margin-top:16px;padding:12px 18px;border-radius:12px;font-size:14px;text-align:center;background:' +
      (type === 'success' ? 'rgba(181,196,177,0.2);color:#6B8B6B;border:1px solid rgba(181,196,177,0.3)' : 'rgba(201,169,110,0.15);color:#B08D4F;border:1px solid rgba(201,169,110,0.3)');
    parent.appendChild(div);
    setTimeout(function () { div.style.opacity = '0'; div.style.transition = 'opacity 0.3s'; setTimeout(function () { div.remove(); }, 300); }, 4000);
  }

  return { init: init };
})();
/* Main Entry — Initialize All Modules */
var PM = PM || {};
(function () {
  'use strict';
  function init() {
    if (PM.preloader) PM.preloader.init();
    if (PM.navigation) PM.navigation.init();
    if (PM.lightbox) PM.lightbox.init();
    if (PM.form) PM.form.init();
    if (PM.animations) PM.animations.initParallax();
  }
  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', init);
  else init();
})();
